function LessonCard({ title, count }) {
  return (
    <article>
      <h3>{title}</h3>
      <p>{count} lessons</p>
    </article>
  )
}

import { useState } from 'react'

function Counter() {
  const [count, setCount] = useState(0)
  return (
    <button onClick={() => setCount(count + 1)}>
      Count: {count}
    </button>
  )
}

import { useEffect, useState } from 'react'

function Page({ title }) {
  useEffect(() => {
    document.title = title
  }, [title])
  return <h1>{title}</h1>
}
